-- Additive SHADOW/RESEARCH/DIAGNOSTIC audit schema. No production or Field 1 table is altered.
CREATE TABLE IF NOT EXISTS shadow_forecast_origin_audit(run_id TEXT NOT NULL,symbol TEXT NOT NULL,timeframe TEXT NOT NULL,forecast_origin TEXT NOT NULL,horizon INTEGER NOT NULL,model_version TEXT NOT NULL,broker_candle_timestamp TEXT NOT NULL,production_decision TEXT NOT NULL,origin_forecast REAL,origin_lower REAL,origin_upper REAL,forecast_mean REAL,forecast_median REAL,quantiles_json TEXT NOT NULL,probability_up REAL,probability_down REAL,probability_neutral REAL,model_weights_json TEXT NOT NULL,model_disagreement REAL,interval_width REAL,calibration_start TEXT,calibration_end TEXT,calibration_fallback_reason TEXT,regime_at_origin TEXT,session_at_origin TEXT,samples_path TEXT,created_at TEXT NOT NULL,PRIMARY KEY(run_id,symbol,timeframe,forecast_origin,horizon,model_version));
CREATE TABLE IF NOT EXISTS shadow_horizon_settlement_audit(run_id TEXT NOT NULL,forecast_origin TEXT NOT NULL,horizon INTEGER NOT NULL,model_version TEXT NOT NULL,maturity_time TEXT,actual REAL,status TEXT NOT NULL,crps REAL,crps_method TEXT,mae REAL,pinball_loss REAL,interval_score REAL,covered INTEGER,interval_width REAL,settled_at TEXT,PRIMARY KEY(run_id,forecast_origin,horizon,model_version));
CREATE TABLE IF NOT EXISTS shadow_governance_audit(run_id TEXT NOT NULL,model_version TEXT NOT NULL,drift_state TEXT NOT NULL,validation_status TEXT NOT NULL,pbo_status TEXT NOT NULL,production_decision TEXT NOT NULL,production_decision_unchanged INTEGER NOT NULL,payload_json TEXT NOT NULL,created_at TEXT NOT NULL,PRIMARY KEY(run_id,model_version));
